={{
"You are Study Aura, an educational quiz generator. Create exactly " + ($json.body.questionCount || 10) + " multiple-choice questions for the topic: " + ($json.body.topic || "General Study") + ". Difficulty: " + ($json.body.difficulty || "easy") + ".\n\n" +
"Selected source context:\n" +
(
  Array.isArray($json.body.selectedSources) && $json.body.selectedSources.length > 0
    ? $json.body.selectedSources.map((source, index) => {
        return (index + 1) + ". " + (source.title || "Untitled Source") + " [" + (source.type || "source") + "]\n" +
          "Summary or content: " + (source.summary || source.value || "No summary provided.");
      }).join("\n\n")
    : "No selected sources were provided. Use the topic only."
) +
"\n\nReturn ONLY valid JSON. No markdown. No code fences.\n" +
"Required JSON format: {\"title\": string, \"questions\": [{\"question\": string, \"choices\": string[], \"answer\": string, \"explanation\": string}]}.\n" +
"Rules:\n" +
"- Each question must have exactly 4 choices.\n" +
"- The answer must exactly match one of the choices.\n" +
"- Explanations should be short and student-friendly.\n" +
"- Prioritize selected source context when available.\n" +
"- Do not include markdown, comments, or text outside JSON."
}}

parameters.jsCode:
const raw = $json.output ?? "";

const cleaned = String(raw)
  .replace(/```json/g, "")
  .replace(/```/g, "")
  .trim();

let quiz;
let fallback = false;

try {
  quiz = JSON.parse(cleaned);

  if (!quiz.title || !quiz.questions || !Array.isArray(quiz.questions)) {
    throw new Error("Invalid quiz format");
  }

  quiz.questions = quiz.questions.map((item, index) => {
    const choices = Array.isArray(item.choices) ? item.choices.slice(0, 4) : [];

    while (choices.length < 4) {
      choices.push(`Option ${choices.length + 1}`);
    }

    const answer = choices.includes(item.answer) ? item.answer : choices[0];

    return {
      question: String(item.question || `Question ${index + 1}`),
      choices,
      answer,
      explanation: String(item.explanation || "Review the related concept and compare the choices carefully.")
    };
  });
} catch (error) {
  fallback = true;
  quiz = {
    title: "Study Aura Quick Quiz",
    questions: [
      {
        question: "What is the best first step when studying a new topic?",
        choices: ["Break it into smaller parts", "Memorize everything immediately", "Skip examples", "Avoid review"],
        answer: "Break it into smaller parts",
        explanation: "Breaking a topic into smaller parts makes it easier to understand and remember."
      }
    ]
  };
}

return [
  {
    json: {
      quiz,
      fallback,
      provider: $json.provider || "unknown"
    }
  }
];

